import{_ as n,c as t,o as e,a1 as s}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Ревью плана: визуальная проверка AI-планов | Plannotator","description":"Изучите функцию ревью планов в Plannotator. Используйте визуальный интерфейс для проверки AI-планов, добавляйте аннотации для одобрения или отклонения, освойте разницу между Approve и Request Changes.","frontmatter":{"title":"Ревью плана: визуальная проверка AI-планов | Plannotator","subtitle":"Основы ревью плана: визуальная проверка AI-планов","description":"Изучите функцию ревью планов в Plannotator. Используйте визуальный интерфейс для проверки AI-планов, добавляйте аннотации для одобрения или отклонения, освойте разницу между Approve и Request Changes.","sidebarTitle":"Освойте ревью плана за 5 минут","tags":["ревью плана","визуальная проверка","аннотации","одобрение","отклонение","Claude Code","OpenCode"],"prerequisite":["start-getting-started"],"order":1},"headers":[],"relativePath":"ru/backnotprop/plannotator/platforms/plan-review-basics/index.md","filePath":"ru/backnotprop/plannotator/platforms/plan-review-basics/index.md"}'),o={name:"ru/backnotprop/plannotator/platforms/plan-review-basics/index.md"};function l(p,a,i,r,d,c){return e(),t("div",null,[...a[0]||(a[0]=[s(`<h1 id="основы-ревью-плана-визуальная-проверка-ai-планов" tabindex="-1">Основы ревью плана: визуальная проверка AI-планов <a class="header-anchor" href="#основы-ревью-плана-визуальная-проверка-ai-планов" aria-label="Permalink to &quot;Основы ревью плана: визуальная проверка AI-планов&quot;">​</a></h1><h2 id="чему-вы-научитесь" tabindex="-1">Чему вы научитесь <a class="header-anchor" href="#чему-вы-научитесь" aria-label="Permalink to &quot;Чему вы научитесь&quot;">​</a></h2><ul><li>✅ Использовать визуальный интерфейс Plannotator для проверки AI-планов</li><li>✅ Выделять текст плана и добавлять различные типы аннотаций (удаление, замена, комментарий)</li><li>✅ Одобрять план, чтобы AI продолжил реализацию</li><li>✅ Отклонять план, отправляя аннотации как обратную связь для AI</li><li>✅ Понимать сценарии использования и различия типов аннотаций</li></ul><h2 id="ваша-текущая-проблема" tabindex="-1">Ваша текущая проблема <a class="header-anchor" href="#ваша-текущая-проблема" aria-label="Permalink to &quot;Ваша текущая проблема&quot;">​</a></h2><p><strong>Проблема 1</strong>: AI-планы реализации приходится читать в терминале — много текста, структура неясна, проверка утомляет.</p><p><strong>Проблема 2</strong>: Чтобы дать AI обратную связь, приходится описывать словами «удали третий абзац», «измени эту функцию» — высокие затраты на коммуникацию, AI может неправильно понять.</p><p><strong>Проблема 3</strong>: Некоторые части плана не требуют изменений, некоторые нужно заменить, некоторые — прокомментировать, но нет инструмента для структурирования этой обратной связи.</p><p><strong>Проблема 4</strong>: Непонятно, как сообщить AI, что план одобрен или требует доработки.</p><p><strong>Plannotator поможет вам</strong>:</p><ul><li>Визуальный UI вместо чтения в терминале — чёткая структура</li><li>Выделите текст и добавьте аннотацию (удаление, замена, комментарий) — точная обратная связь</li><li>Аннотации автоматически преобразуются в структурированные данные — AI точно понимает ваши намерения</li><li>Одобрение или отклонение одним кликом — AI реагирует мгновенно</li></ul><h2 id="когда-использовать-этот-подход" tabindex="-1">Когда использовать этот подход <a class="header-anchor" href="#когда-использовать-этот-подход" aria-label="Permalink to &quot;Когда использовать этот подход&quot;">​</a></h2><p><strong>Сценарии использования</strong>:</p><ul><li>AI Agent завершил план и вызвал <code>ExitPlanMode</code> (Claude Code)</li><li>AI Agent вызвал инструмент <code>submit_plan</code> (OpenCode)</li><li>Необходимо проверить AI-план реализации</li><li>Необходимо точно передать замечания по плану</li></ul><p><strong>Неподходящие сценарии</strong>:</p><ul><li>Прямая реализация кода AI (без ревью плана)</li><li>План уже одобрен, нужно проверить фактические изменения кода (используйте функцию code review)</li></ul><h2 id="🎒-подготовка" tabindex="-1">🎒 Подготовка <a class="header-anchor" href="#🎒-подготовка" aria-label="Permalink to &quot;🎒 Подготовка&quot;">​</a></h2><p><strong>Предварительные требования</strong>:</p><ul><li>✅ Установлен Plannotator CLI (см. <a href="./../start/getting-started/">Быстрый старт</a>)</li><li>✅ Настроен плагин Claude Code или OpenCode (см. соответствующее руководство по установке)</li><li>✅ AI Agent поддерживает ревью плана (Claude Code 2.1.7+ или OpenCode)</li></ul><p><strong>Способы запуска</strong>:</p><ul><li><strong>Claude Code</strong>: После завершения плана AI автоматически вызывает <code>ExitPlanMode</code>, Plannotator запускается автоматически</li><li><strong>OpenCode</strong>: AI вызывает инструмент <code>submit_plan</code>, Plannotator запускается автоматически</li></ul><h2 id="основная-концепция" tabindex="-1">Основная концепция <a class="header-anchor" href="#основная-концепция" aria-label="Permalink to &quot;Основная концепция&quot;">​</a></h2><h3 id="что-такое-ревью-плана" tabindex="-1">Что такое ревью плана <a class="header-anchor" href="#что-такое-ревью-плана" aria-label="Permalink to &quot;Что такое ревью плана&quot;">​</a></h3><p><strong>Ревью плана</strong> — это основная функция Plannotator для визуальной проверки AI-планов реализации.</p><div class="info custom-block"><p class="custom-block-title">Зачем нужно ревью плана?</p><p>После генерации плана AI обычно спрашивает «Этот план подходит?» или «Начать реализацию?». Без визуального инструмента приходится читать текстовый план в терминале и отвечать размытыми фразами вроде «ок», «нет, измени XX». Plannotator позволяет просматривать план в визуальном интерфейсе, точно выделять части, требующие изменений, добавлять структурированные аннотации — AI легче понимает ваши намерения.</p></div><h3 id="рабочии-процесс" tabindex="-1">Рабочий процесс <a class="header-anchor" href="#рабочии-процесс" aria-label="Permalink to &quot;Рабочий процесс&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────┐</span></span>
<span class="line"><span>│  AI Agent      │</span></span>
<span class="line"><span>│  (генерация    │</span></span>
<span class="line"><span>│   плана)       │</span></span>
<span class="line"><span>└────────┬────────┘</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>         │ ExitPlanMode / submit_plan</span></span>
<span class="line"><span>         ▼</span></span>
<span class="line"><span>┌─────────────────┐</span></span>
<span class="line"><span>│ Plannotator UI  │  ← браузер открывается автоматически</span></span>
<span class="line"><span>│                 │</span></span>
<span class="line"><span>│ ┌───────────┐  │</span></span>
<span class="line"><span>│ │ Содержимое │  │</span></span>
<span class="line"><span>│ │ плана      │  │</span></span>
<span class="line"><span>│ │ (Markdown) │  │</span></span>
<span class="line"><span>│ └───────────┘  │</span></span>
<span class="line"><span>│       │         │</span></span>
<span class="line"><span>│       │ выделение текста</span></span>
<span class="line"><span>│       ▼         │</span></span>
<span class="line"><span>│ ┌───────────┐  │</span></span>
<span class="line"><span>│ │ Добавление │  │</span></span>
<span class="line"><span>│ │ аннотации  │  │</span></span>
<span class="line"><span>│ │ Delete/    │  │</span></span>
<span class="line"><span>│ │ Replace/   │  │</span></span>
<span class="line"><span>│ │ Comment    │  │</span></span>
<span class="line"><span>│ └───────────┘  │</span></span>
<span class="line"><span>│       │         │</span></span>
<span class="line"><span>│       ▼         │</span></span>
<span class="line"><span>│ ┌───────────┐  │</span></span>
<span class="line"><span>│ │ Решение   │  │</span></span>
<span class="line"><span>│ │ Approve/  │  │</span></span>
<span class="line"><span>│ │ Request   │  │</span></span>
<span class="line"><span>│ │ Changes   │  │</span></span>
<span class="line"><span>│ └───────────┘  │</span></span>
<span class="line"><span>└────────┬────────┘</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>         │ {&quot;behavior&quot;: &quot;allow&quot;} или</span></span>
<span class="line"><span>         │ {&quot;behavior&quot;: &quot;deny&quot;, &quot;message&quot;: &quot;...&quot;}</span></span>
<span class="line"><span>         ▼</span></span>
<span class="line"><span>┌─────────────────┐</span></span>
<span class="line"><span>│  AI Agent      │</span></span>
<span class="line"><span>│  (продолжение  │</span></span>
<span class="line"><span>│   реализации)  │</span></span>
<span class="line"><span>└─────────────────┘</span></span></code></pre></div><h3 id="типы-аннотации" tabindex="-1">Типы аннотаций <a class="header-anchor" href="#типы-аннотации" aria-label="Permalink to &quot;Типы аннотаций&quot;">​</a></h3><p>Plannotator поддерживает четыре типа аннотаций, каждый с разным назначением:</p><table tabindex="0"><thead><tr><th>Тип аннотации</th><th>Назначение</th><th>Обратная связь для AI</th></tr></thead><tbody><tr><td><strong>Delete</strong></td><td>Удаление ненужного контента</td><td>&quot;Удалить: [выделенный текст]&quot;</td></tr><tr><td><strong>Replace</strong></td><td>Замена на лучший контент</td><td>&quot;Заменить: [выделенный текст] на [ваш текст]&quot;</td></tr><tr><td><strong>Comment</strong></td><td>Комментарий к фрагменту без требования изменений</td><td>&quot;Комментарий: [выделенный текст]. Пояснение: [ваш комментарий]&quot;</td></tr><tr><td><strong>Global Comment</strong></td><td>Глобальный комментарий, не привязанный к конкретному тексту</td><td>&quot;Глобальный комментарий: [ваш комментарий]&quot;</td></tr></tbody></table><h3 id="approve-vs-request-changes" tabindex="-1">Approve vs Request Changes <a class="header-anchor" href="#approve-vs-request-changes" aria-label="Permalink to &quot;Approve vs Request Changes&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Тип решения</th><th>Действие</th><th>Обратная связь для AI</th><th>Сценарий использования</th></tr></thead><tbody><tr><td><strong>Approve</strong></td><td>Нажать кнопку Approve</td><td><code>{&quot;behavior&quot;: &quot;allow&quot;}</code></td><td>План в порядке, одобрить сразу</td></tr><tr><td><strong>Request Changes</strong></td><td>Нажать кнопку Request Changes</td><td><code>{&quot;behavior&quot;: &quot;deny&quot;, &quot;message&quot;: &quot;...&quot;}</code></td><td>Есть замечания для исправления</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Различия между Claude Code и OpenCode</p><ul><li><strong>Claude Code</strong>: При Approve аннотации не отправляются (игнорируются)</li><li><strong>OpenCode</strong>: При Approve аннотации можно отправить как примечание (опционально)</li></ul><p><strong>При отклонении плана</strong>: На обеих платформах аннотации отправляются AI</p></div><h2 id="пошаговое-руководство" tabindex="-1">Пошаговое руководство <a class="header-anchor" href="#пошаговое-руководство" aria-label="Permalink to &quot;Пошаговое руководство&quot;">​</a></h2><h3 id="шаг-1-запуск-ревью-плана" tabindex="-1">Шаг 1: Запуск ревью плана <a class="header-anchor" href="#шаг-1-запуск-ревью-плана" aria-label="Permalink to &quot;Шаг 1: Запуск ревью плана&quot;">​</a></h3><p><strong>Пример для Claude Code</strong>:</p><p>В Claude Code начните диалог с AI, попросив сгенерировать план реализации:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Пользователь: Помоги мне составить план реализации модуля аутентификации</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Claude: Хорошо, вот план реализации:</span></span>
<span class="line"><span>1. Создать модель пользователя</span></span>
<span class="line"><span>2. Реализовать API регистрации</span></span>
<span class="line"><span>3. Реализовать API входа</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span>(AI вызывает ExitPlanMode)</span></span></code></pre></div><p><strong>Пример для OpenCode</strong>:</p><p>В OpenCode AI автоматически вызывает инструмент <code>submit_plan</code>.</p><p><strong>Что вы должны увидеть</strong>:</p><ol><li>Браузер автоматически открывает Plannotator UI</li><li>Отображается содержимое AI-плана (в формате Markdown)</li><li>Внизу страницы кнопки «Approve» и «Request Changes»</li></ol><h3 id="шаг-2-просмотр-содержимого-плана" tabindex="-1">Шаг 2: Просмотр содержимого плана <a class="header-anchor" href="#шаг-2-просмотр-содержимого-плана" aria-label="Permalink to &quot;Шаг 2: Просмотр содержимого плана&quot;">​</a></h3><p>Просмотрите план в браузере:</p><ul><li>План отрендерен в формате Markdown: заголовки, абзацы, списки, блоки кода</li><li>Можно прокручивать для просмотра всего плана</li><li>Поддержка переключения светлой/тёмной темы (кнопка в правом верхнем углу)</li></ul><h3 id="шаг-3-выделение-текста-и-добавление-аннотации" tabindex="-1">Шаг 3: Выделение текста и добавление аннотаций <a class="header-anchor" href="#шаг-3-выделение-текста-и-добавление-аннотации" aria-label="Permalink to &quot;Шаг 3: Выделение текста и добавление аннотаций&quot;">​</a></h3><p><strong>Добавление аннотации Delete</strong>:</p><ol><li>Выделите мышью текст, который нужно удалить</li><li>Нажмите кнопку <strong>Delete</strong> во всплывающей панели инструментов</li><li>Текст будет отмечен стилем удаления (красное зачёркивание)</li></ol><p><strong>Добавление аннотации Replace</strong>:</p><ol><li>Выделите мышью текст, который нужно заменить</li><li>Нажмите кнопку <strong>Replace</strong> во всплывающей панели инструментов</li><li>Введите новый текст в появившемся поле ввода</li><li>Нажмите Enter или кнопку подтверждения</li><li>Исходный текст будет отмечен стилем замены (жёлтый фон), ниже отобразится текст замены</li></ol><p><strong>Добавление аннотации Comment</strong>:</p><ol><li>Выделите мышью текст, который хотите прокомментировать</li><li>Нажмите кнопку <strong>Comment</strong> во всплывающей панели инструментов</li><li>Введите комментарий в появившемся поле ввода</li><li>Нажмите Enter или кнопку подтверждения</li><li>Текст будет отмечен стилем комментария (синяя подсветка), комментарий отобразится в боковой панели</li></ol><p><strong>Добавление Global Comment</strong>:</p><ol><li>Нажмите кнопку <strong>Add Global Comment</strong> в правом верхнем углу страницы</li><li>Введите глобальный комментарий в появившемся поле ввода</li><li>Нажмите Enter или кнопку подтверждения</li><li>Комментарий отобразится в разделе «Global Comments» боковой панели</li></ol><p><strong>Что вы должны увидеть</strong>:</p><ul><li>После выделения текста сразу появляется панель инструментов (Delete, Replace, Comment)</li><li>После добавления аннотации текст отображается с соответствующим стилем (зачёркивание, фон, подсветка)</li><li>В боковой панели отображается список всех аннотаций, клик переходит к соответствующему месту</li><li>Можно нажать кнопку <strong>удаления</strong> рядом с аннотацией, чтобы её убрать</li></ul><h3 id="шаг-4-одобрение-плана" tabindex="-1">Шаг 4: Одобрение плана <a class="header-anchor" href="#шаг-4-одобрение-плана" aria-label="Permalink to &quot;Шаг 4: Одобрение плана&quot;">​</a></h3><p><strong>Если план в порядке</strong>:</p><p>Нажмите кнопку <strong>Approve</strong> внизу страницы.</p><p><strong>Что вы должны увидеть</strong>:</p><ul><li>Браузер автоматически закрывается (с задержкой 1,5 секунды)</li><li>В терминале Claude Code/OpenCode отображается, что план одобрен</li><li>AI продолжает реализацию плана</li></ul><div class="info custom-block"><p class="custom-block-title">Поведение Approve</p><ul><li><strong>Claude Code</strong>: Отправляется только <code>{&quot;behavior&quot;: &quot;allow&quot;}</code>, аннотации игнорируются</li><li><strong>OpenCode</strong>: Отправляется <code>{&quot;behavior&quot;: &quot;allow&quot;}</code>, аннотации можно отправить как примечание (опционально)</li></ul></div><h3 id="шаг-5-отклонение-плана-request-changes" tabindex="-1">Шаг 5: Отклонение плана (Request Changes) <a class="header-anchor" href="#шаг-5-отклонение-плана-request-changes" aria-label="Permalink to &quot;Шаг 5: Отклонение плана (Request Changes)&quot;">​</a></h3><p><strong>Если план требует доработки</strong>:</p><ol><li>Добавьте необходимые аннотации (Delete, Replace, Comment)</li><li>Нажмите кнопку <strong>Request Changes</strong> внизу страницы</li><li>Браузер покажет диалог подтверждения</li></ol><p><strong>Что вы должны увидеть</strong>:</p><ul><li>Диалог подтверждения «Send X annotations to AI?»</li><li>После подтверждения браузер автоматически закрывается</li><li>В терминале Claude Code/OpenCode отображается содержимое обратной связи</li><li>AI доработает план на основе обратной связи</li></ul><div class="tip custom-block"><p class="custom-block-title">Поведение Request Changes</p><ul><li><strong>Claude Code</strong> и <strong>OpenCode</strong>: Оба отправляют <code>{&quot;behavior&quot;: &quot;deny&quot;, &quot;message&quot;: &quot;...&quot;}</code></li><li>Аннотации преобразуются в структурированный Markdown-текст</li><li>AI доработает план и снова вызовет ExitPlanMode/submit_plan</li></ul></div><h3 id="шаг-6-просмотр-содержимого-обратнои-связи-опционально" tabindex="-1">Шаг 6: Просмотр содержимого обратной связи (опционально) <a class="header-anchor" href="#шаг-6-просмотр-содержимого-обратнои-связи-опционально" aria-label="Permalink to &quot;Шаг 6: Просмотр содержимого обратной связи (опционально)&quot;">​</a></h3><p>Если хотите увидеть, что Plannotator отправил AI, посмотрите в терминале:</p><p><strong>Claude Code</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Plan rejected by user</span></span>
<span class="line"><span>Please modify the plan based on the following feedback:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[структурированное содержимое аннотаций]</span></span></code></pre></div><p><strong>OpenCode</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;feedback&gt;</span></span>
<span class="line"><span>[структурированное содержимое аннотаций]</span></span>
<span class="line"><span>&lt;/feedback&gt;</span></span></code></pre></div><h2 id="контрольныи-список-✅" tabindex="-1">Контрольный список ✅ <a class="header-anchor" href="#контрольныи-список-✅" aria-label="Permalink to &quot;Контрольный список ✅&quot;">​</a></h2><p>После выполнения всех шагов вы должны уметь:</p><ul><li>[ ] После запуска ревью плана AI браузер автоматически открывает Plannotator UI</li><li>[ ] Выделять текст плана и добавлять аннотации Delete, Replace, Comment</li><li>[ ] Добавлять Global Comment</li><li>[ ] Просматривать все аннотации в боковой панели и переходить к соответствующим местам</li><li>[ ] Нажать Approve — браузер закрывается, AI продолжает реализацию</li><li>[ ] Нажать Request Changes — браузер закрывается, AI дорабатывает план</li></ul><p><strong>Если какой-то шаг не работает</strong>, см.:</p><ul><li><a href="./../../faq/common-problems/">Частые проблемы</a></li><li><a href="./../../start/installation-claude-code/">Руководство по установке Claude Code</a></li><li><a href="./../../start/installation-opencode/">Руководство по установке OpenCode</a></li></ul><h2 id="типичные-ошибки" tabindex="-1">Типичные ошибки <a class="header-anchor" href="#типичные-ошибки" aria-label="Permalink to &quot;Типичные ошибки&quot;">​</a></h2><p><strong>Ошибка 1</strong>: После выделения текста панель инструментов не появляется</p><p><strong>Причина</strong>: Возможно, выделен текст внутри блока кода или выделение охватывает несколько элементов.</p><p><strong>Решение</strong>:</p><ul><li>Старайтесь выделять текст в пределах одного абзаца или элемента списка</li><li>Для блоков кода используйте аннотацию Comment, не выделяйте несколько строк</li></ul><p><strong>Ошибка 2</strong>: После добавления аннотации Replace текст замены не отображается</p><p><strong>Причина</strong>: Поле ввода текста замены могло быть отправлено некорректно.</p><p><strong>Решение</strong>:</p><ul><li>После ввода текста замены нажмите Enter или кнопку подтверждения</li><li>Проверьте, отображается ли текст замены в боковой панели</li></ul><p><strong>Ошибка 3</strong>: После нажатия Approve или Request Changes браузер не закрывается</p><p><strong>Причина</strong>: Возможна ошибка сервера или проблемы с сетью.</p><p><strong>Решение</strong>:</p><ul><li>Проверьте сообщения об ошибках в терминале</li><li>Закройте браузер вручную</li><li>Если проблема сохраняется, см. <a href="./../../faq/troubleshooting/">Устранение неполадок</a></li></ul><p><strong>Ошибка 4</strong>: AI получил обратную связь, но не внёс изменения согласно аннотациям</p><p><strong>Причина</strong>: AI мог неправильно понять намерение аннотации.</p><p><strong>Решение</strong>:</p><ul><li>Попробуйте использовать более явные аннотации (Replace яснее, чем Comment)</li><li>Используйте Comment для добавления подробных пояснений</li><li>Если проблема сохраняется, отклоните план повторно и скорректируйте аннотации</li></ul><p><strong>Ошибка 5</strong>: После добавления нескольких аннотаций Delete AI удалил только часть контента</p><p><strong>Причина</strong>: Несколько аннотаций Delete могут пересекаться или конфликтовать.</p><p><strong>Решение</strong>:</p><ul><li>Убедитесь, что диапазоны текста аннотаций Delete не пересекаются</li><li>Если нужно удалить большой фрагмент, выделите весь абзац за один раз</li></ul><h2 id="итоги-урока" tabindex="-1">Итоги урока <a class="header-anchor" href="#итоги-урока" aria-label="Permalink to &quot;Итоги урока&quot;">​</a></h2><p>Ревью плана — это основная функция Plannotator для визуальной проверки AI-планов:</p><p><strong>Основные операции</strong>:</p><ol><li><strong>Запуск</strong>: AI вызывает <code>ExitPlanMode</code> или <code>submit_plan</code>, браузер автоматически открывает UI</li><li><strong>Просмотр</strong>: Просмотр содержимого плана в визуальном интерфейсе (формат Markdown)</li><li><strong>Аннотации</strong>: Выделение текста, добавление Delete, Replace, Comment или Global Comment</li><li><strong>Решение</strong>: Нажатие Approve (одобрить) или Request Changes (отклонить)</li><li><strong>Обратная связь</strong>: Аннотации преобразуются в структурированные данные, AI продолжает или дорабатывает план</li></ol><p><strong>Типы аннотаций</strong>:</p><ul><li><strong>Delete</strong>: Удаление ненужного контента</li><li><strong>Replace</strong>: Замена на лучший контент</li><li><strong>Comment</strong>: Комментарий к фрагменту без требования изменений</li><li><strong>Global Comment</strong>: Глобальный комментарий, не привязанный к конкретному тексту</li></ul><p><strong>Типы решений</strong>:</p><ul><li><strong>Approve</strong>: План в порядке, одобрить сразу (Claude Code игнорирует аннотации)</li><li><strong>Request Changes</strong>: Есть замечания, аннотации отправляются AI</li></ul><h2 id="анонс-следующего-урока" tabindex="-1">Анонс следующего урока <a class="header-anchor" href="#анонс-следующего-урока" aria-label="Permalink to &quot;Анонс следующего урока&quot;">​</a></h2><blockquote><p>В следующем уроке мы изучим <strong><a href="./../plan-review-annotations/">Добавление аннотаций к плану</a></strong>.</p><p>Вы узнаете:</p><ul><li>Как точно использовать аннотации Delete, Replace, Comment</li><li>Как добавлять аннотации к изображениям</li><li>Как редактировать и удалять аннотации</li><li>Лучшие практики и типичные сценарии использования аннотаций</li></ul></blockquote><hr><h2 id="приложение-справочник-по-исходному-коду" tabindex="-1">Приложение: справочник по исходному коду <a class="header-anchor" href="#приложение-справочник-по-исходному-коду" aria-label="Permalink to &quot;Приложение: справочник по исходному коду&quot;">​</a></h2><details><summary><strong>Нажмите, чтобы развернуть расположение исходного кода</strong></summary><blockquote><p>Дата обновления: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Функция</th><th>Путь к файлу</th><th>Строки</th></tr></thead><tbody><tr><td>UI ревью плана</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/editor/App.tsx#L1-L200" target="_blank" rel="noreferrer"><code>packages/editor/App.tsx</code></a></td><td>1-200</td></tr><tr><td>Определение типов аннотаций</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/types.ts#L1-L70" target="_blank" rel="noreferrer"><code>packages/ui/types.ts</code></a></td><td>1-70</td></tr><tr><td>Сервер ревью плана</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/index.ts#L91-L310" target="_blank" rel="noreferrer"><code>packages/server/index.ts</code></a></td><td>91-310</td></tr><tr><td>API: получение содержимого плана</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/index.ts#L132-L134" target="_blank" rel="noreferrer"><code>packages/server/index.ts</code></a></td><td>132-134</td></tr><tr><td>API: одобрение плана</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/index.ts#L201-L277" target="_blank" rel="noreferrer"><code>packages/server/index.ts</code></a></td><td>201-277</td></tr><tr><td>API: отклонение плана</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/index.ts#L280-L309" target="_blank" rel="noreferrer"><code>packages/server/index.ts</code></a></td><td>280-309</td></tr><tr><td>Компонент Viewer</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/components/Viewer.tsx#L1-L100" target="_blank" rel="noreferrer"><code>packages/ui/components/Viewer.tsx</code></a></td><td>1-100</td></tr><tr><td>Компонент AnnotationPanel</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/components/AnnotationPanel.tsx#L1-L50" target="_blank" rel="noreferrer"><code>packages/ui/components/AnnotationPanel.tsx</code></a></td><td>1-50</td></tr></tbody></table><p><strong>Ключевые типы</strong>:</p><ul><li><code>AnnotationType</code>: перечисление типов аннотаций (DELETION, INSERTION, REPLACEMENT, COMMENT, GLOBAL_COMMENT) (<code>packages/ui/types.ts:1-7</code>)</li><li><code>Annotation</code>: интерфейс аннотации (<code>packages/ui/types.ts:11-33</code>)</li><li><code>Block</code>: интерфейс блока плана (<code>packages/ui/types.ts:35-44</code>)</li></ul><p><strong>Ключевые функции</strong>:</p><ul><li><code>startPlannotatorServer()</code>: запуск сервера ревью плана (<code>packages/server/index.ts:91</code>)</li><li><code>parseMarkdownToBlocks()</code>: парсинг Markdown в блоки (<code>packages/ui/utils/parser.ts</code>)</li></ul><p><strong>API-маршруты</strong>:</p><ul><li><code>GET /api/plan</code>: получение содержимого плана (<code>packages/server/index.ts:132</code>)</li><li><code>POST /api/approve</code>: одобрение плана (<code>packages/server/index.ts:201</code>)</li><li><code>POST /api/deny</code>: отклонение плана (<code>packages/server/index.ts:280</code>)</li></ul><p><strong>Бизнес-правила</strong>:</p><ul><li>Claude Code при одобрении не отправляет аннотации (<code>apps/hook/server/index.ts:132</code>)</li><li>OpenCode при одобрении может отправить аннотации как примечание (<code>apps/opencode-plugin/index.ts:270</code>)</li><li>При отклонении плана аннотации всегда отправляются (<code>apps/hook/server/index.ts:154</code>)</li></ul></details>`,112)])])}const h=n(o,[["render",l]]);export{u as __pageData,h as default};
